script:
// 1. تحديد ترحيب مخصص باسم الموظف المسجل حالياً
const user_fullname = frappe.session.user_fullname || "مستأجر الفجر";
let greeting = "أهلاً بك";
const hour = new Date().getHours();

if (hour >= 5 && hour < 12) {
    greeting = "صباح الخير";
} else if (hour >= 12 && hour < 18) {
    greeting = "مساء الخير";
} else {
    greeting = "مساء الخير";
}

// استخدام root_element كمحدد أصل للوصول لعنوان الترحيب
const welcome_text = root_element.querySelector('.greeting-text');
if (welcome_text) {
    welcome_text.innerHTML = `${greeting}، ${user_fullname} 👋`;
}

// 2. تشغيل الساعة التفاعلية المتزامنة بالثانية
function start_live_clock() {
    const clock_time = new Date();
    const date_options = { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' };
    const arab_date = clock_time.toLocaleDateString('ar-EG', date_options);
    const arab_time = clock_time.toLocaleTimeString('ar-EG', { hour: '2-digit', minute: '2-digit', second: '2-digit' });

    // استخدام root_element للوصول لعناصر الساعة والتاريخ داخل البانر
    const date_el = root_element.querySelector('#live-date');
    const time_el = root_element.querySelector('#live-time');

    if (date_el) date_el.innerHTML = arab_date;
    if (time_el) time_el.innerHTML = arab_time;
}

start_live_clock();
// تفعيل التحديث التلقائي المستمر كل ثانية
const clock_interval = setInterval(start_live_clock, 1000);

// تنظيف مؤقت الساعة فور مغادرة الموظف لمساحة العمل لمنع استهلاك عتاد الجهاز
frappe.dom.on_clean_up(root_element, () => {
    clearInterval(clock_interval);
});

// 3. جلب الإحصائيات الحقيقية من قاعدة البيانات وعرضها في الكروت تلقائياً
// أ. حساب عدد عقود الحجز المعتمدة والنشطة حالياً
frappe.db.count('Car Booking', { docstatus: 1 })
    .then(count => {
        const rentals_el = root_element.querySelector('#active-rentals');
        if (rentals_el) {
            rentals_el.innerHTML = count > 0 ? `${count} عقد نشط` : 'لا توجد حجوزات نشطة';
        }
    });

// ب. حساب عدد شفتات الموظفين المجدولة لتاريخ اليوم
const today_date = frappe.datetime.get_today();
frappe.db.count('Shift Assignment', { start_date: today_date })
    .then(count => {
        const shifts_el = root_element.querySelector('#today-shifts');
        if (shifts_el) {
            shifts_el.innerHTML = count > 0 ? `${count} شفت مجدول` : 'لا توجد شفتات اليوم';
        }
    });

