script:
// يتفاعل مع HTML أعلاه، سيتم استدعاء إلى root_element كمحدد أصل
let cards = root_element.querySelectorAll('.gcb-card');

cards.forEach(function (card) {
  card.addEventListener('mouseenter', function () {
    card.style.borderColor = '#4caf50';
  });
  card.addEventListener('mouseleave', function () {
    card.style.borderColor = '';
  });

  card.addEventListener('click', function (e) {
    let ripple = document.createElement('span');
    ripple.style.position = 'absolute';
    ripple.style.borderRadius = '50%';
    ripple.style.background = 'rgba(76,175,80,0.25)';
    ripple.style.transform = 'scale(0)';
    ripple.style.animation = 'gcb-ripple 0.5s ease-out';
    ripple.style.left = (e.offsetX - 10) + 'px';
    ripple.style.top = (e.offsetY - 10) + 'px';
    ripple.style.width = ripple.style.height = '20px';
    ripple.style.pointerEvents = 'none';
    card.appendChild(ripple);
    setTimeout(function () { ripple.remove(); }, 500);
  });
});

if (!document.getElementById('gcb-ripple-style')) {
  let style = document.createElement('style');
  style.id = 'gcb-ripple-style';
  style.textContent = '@keyframes gcb-ripple { to { transform: scale(6); opacity: 0; } }';
  document.head.appendChild(style);
}

style:
.gcb-wrap {
  direction: rtl;
  font-family: inherit;
  --gcb-green-1: #1e8e3e;
  --gcb-green-2: #4caf50;
  --gcb-green-light: #eafaf0;
  --gcb-text: #1f2a24;
  --gcb-muted: #6b7b72;
  --gcb-border: #e3ede6;
}

.gcb-hero {
  background: linear-gradient(120deg, #0f9146 0%, #3faa4a 45%, #6abd27 75%, #8fcf1b 100%);
  border-radius: 14px;
  padding: 28px 32px;
  margin-bottom: 20px;
  text-align: left;
  box-shadow: 0 6px 18px rgba(30, 142, 62, 0.25);
}

.gcb-hero-text h2 {
  color: #fff;
  font-size: 28px;
  font-weight: 800;
  margin: 0 0 6px;
  letter-spacing: 0.5px;
}

.gcb-hero-text p {
  color: rgba(255, 255, 255, 0.9);
  margin: 0;
  font-size: 14px;
}

.gcb-grid-top {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 14px;
  margin-bottom: 14px;
}

.gcb-card-featured {
  padding: 22px 20px;
  background: linear-gradient(135deg, #fff, var(--gcb-green-light));
  border-color: #cdeed9;
}

.gcb-card-featured .gcb-icon {
  width: 48px;
  height: 48px;
  background: linear-gradient(135deg, var(--gcb-green-1), var(--gcb-green-2));
  color: #fff;
}

.gcb-card-featured .gcb-icon svg {
  width: 26px;
  height: 26px;
}

.gcb-card-featured .gcb-label {
  font-size: 16px;
}

.gcb-grid {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(180px, 1fr));
  gap: 14px;
}

.gcb-card {
  display: flex;
  align-items: center;
  gap: 12px;
  background: #fff;
  border: 1px solid var(--gcb-border);
  border-radius: 12px;
  padding: 16px 18px;
  text-decoration: none;
  color: var(--gcb-text);
  transition: transform 0.18s ease, box-shadow 0.18s ease, border-color 0.18s ease;
  position: relative;
  overflow: hidden;
}

.gcb-card:hover {
  transform: translateY(-3px);
  box-shadow: 0 10px 22px rgba(30, 142, 62, 0.15);
  border-color: var(--gcb-green-2);
}

.gcb-icon {
  flex-shrink: 0;
  width: 42px;
  height: 42px;
  display: flex;
  align-items: center;
  justify-content: center;
  border-radius: 10px;
  background: var(--gcb-green-light);
  color: var(--gcb-green-1);
}

.gcb-icon svg {
  width: 22px;
  height: 22px;
}

.gcb-label {
  font-size: 14.5px;
  font-weight: 600;
  color: var(--gcb-text);
}

.gcb-card::after {
  content: "";
  position: absolute;
  inset: 0;
  background: linear-gradient(135deg, rgba(76, 175, 80, 0.06), transparent);
  opacity: 0;
  transition: opacity 0.18s ease;
}

.gcb-card:hover::after {
  opacity: 1;
}

@media (max-width: 640px) {
  .gcb-hero { padding: 22px 18px; }
  .gcb-hero-text h2 { font-size: 22px; }
  .gcb-grid-top { grid-template-columns: 1fr; }
  .gcb-grid { grid-template-columns: repeat(auto-fill, minmax(140px, 1fr)); }
}
.gcb-hero-logo {
  background: none;
  box-shadow: none;
  padding: 0;
  flex-shrink: 0;
}
.gcb-hero-logo img {
  height: 52px;
  width: auto;
  max-width: 210px;
  display: inline-block;
  filter: brightness(0) invert(1) drop-shadow(0 2px 4px rgba(0,0,0,.18));
}

