  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(180px, 1fr));
  gap: 14px;
}

.gcb-card {
  display: flex;
  align-items: center;
  gap: 12px;
  background: #fff;
  border: 1px solid var(--gcb-border);
  border-radius: 12px;
  padding: 16px 18px;
  text-decoration: none;
  color: var(--gcb-text);
  transition: transform 0.18s ease, box-shadow 0.18s ease, border-color 0.18s ease;
  position: relative;
  overflow: hidden;
}

.gcb-card:hover {
  transform: translateY(-3px);
  box-shadow: 0 10px 22px rgba(30, 142, 62, 0.15);
  border-color: var(--gcb-green-2);
}

.gcb-icon {
  flex-shrink: 0;
  width: 42px;
  height: 42px;
  display: flex;
  align-items: center;
  justify-content: center;
  border-radius: 10px;
  background: var(--gcb-green-light);
  color: var(--gcb-green-1);
}

.gcb-icon svg {
  width: 22px;
  height: 22px;
}

.gcb-label {
  font-size: 14.5px;
  font-weight: 600;
  color: var(--gcb-text);
}

.gcb-card::after {
  content: "";
  position: absolute;
  inset: 0;
  background: linear-gradient(135deg, rgba(76, 175, 80, 0.06), transparent);
  opacity: 0;
  transition: opacity 0.18s ease;
}

.gcb-card:hover::after {
  opacity: 1;
}

@media (max-width: 640px) {
  .gcb-hero { padding: 22px 18px; }
  .gcb-hero-text h2 { font-size: 22px; }
  .gcb-grid-top { grid-template-columns: 1fr; }
  .gcb-grid { grid-template-columns: repeat(auto-fill, minmax(140px, 1fr)); }
}
.gcb-hero-logo {
  background: none;
  box-shadow: none;
  padding: 0;
  flex-shrink: 0;
}
.gcb-hero-logo img {
  height: 52px;
  width: auto;
  max-width: 210px;
  display: inline-block;
  filter: brightness(0) invert(1) drop-shadow(0 2px 4px rgba(0,0,0,.18));
}
